import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';

export default function LoginPage() {
  const { signInWithGoogle, signInWithEmail, user } = useAuth();
  const brand = useBrand();
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);

  // Redirect if already logged in
  if (user) {
    navigate(brand.homePath);
    return null;
  }

  async function handleEmailLogin(e: React.FormEvent) {
    e.preventDefault();
    setError('');
    setLoading(true);
    const { error: err } = await signInWithEmail(email, password);
    setLoading(false);
    if (err) {
      setError(err);
    } else {
      const saved = sessionStorage.getItem('tms_redirect');
      if (saved) {
        sessionStorage.removeItem('tms_redirect');
        navigate(saved);
      } else {
        navigate(brand.homePath);
      }
    }
  }

  async function handleGoogle() {
    try {
      await signInWithGoogle(brand.homePath);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Google login failed');
    }
  }

  return (
    <div style={{ maxWidth: '420px', margin: '4rem auto', padding: '0 1.5rem' }}>
      <div className="glass-panel" style={{ padding: '2.5rem 2rem', textAlign: 'center' }}>
        <h2 style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>
          <i className="fa-solid fa-arrow-right-to-bracket" style={{ color: 'var(--primary-color)' }} /> Log In
        </h2>
        <p style={{ color: 'var(--text-secondary)', marginBottom: '1.5rem', lineHeight: 1.5 }}>
          Welcome back! Log in to access your saved tailored resumes.
        </p>

        <button onClick={handleGoogle} className="btn auth-btn google-btn">
          <img
            src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg"
            alt="Google"
            style={{ width: '20px', height: '20px', marginRight: '10px', display: 'inline-block', verticalAlign: 'middle' }}
          />
          Log In with Google
        </button>

        <div className="divider"><span>OR</span></div>

        <form onSubmit={handleEmailLogin} style={{ textAlign: 'left' }}>
          <div style={{ marginBottom: '1rem' }}>
            <label htmlFor="email-input" style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', marginBottom: '0.3rem', display: 'block' }}>
              Email
            </label>
            <input
              id="email-input"
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="you@example.com"
              required
              autoComplete="email"
            />
          </div>

          <div style={{ marginBottom: '1rem' }}>
            <label htmlFor="password-input" style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', marginBottom: '0.3rem', display: 'block' }}>
              Password
            </label>
            <div style={{ position: 'relative' }}>
              <input
                id="password-input"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Your password"
                required
                minLength={6}
                style={{ paddingRight: '2.5rem' }}
              />
              <button
                type="button"
                onClick={() => setShowPassword(v => !v)}
                style={{
                  position: 'absolute',
                  right: '0.5rem',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'transparent',
                  border: 'none',
                  color: 'var(--text-secondary)',
                  cursor: 'pointer',
                }}
              >
                <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`} />
              </button>
            </div>
          </div>

          {error && (
            <p style={{ color: '#ef4444', fontSize: '0.82rem', marginBottom: '1rem' }}>{error}</p>
          )}

          <button type="submit" disabled={loading} className="btn secondary-btn large-action-btn">
            {loading ? 'Signing in...' : 'Sign In'}
          </button>

          <p style={{ textAlign: 'right', marginTop: '0.5rem' }}>
            <Link to="/forgot-password" style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
              Forgot password?
            </Link>
          </p>
        </form>

        <p style={{ marginTop: '1.5rem', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
          Don't have an account?{' '}
          <Link to="/signup" style={{ color: 'var(--primary-color)', fontWeight: 600 }}>
            Sign Up
          </Link>
        </p>
      </div>
    </div>
  );
}
